}

// NewGormRepository creates a new bets repository backed by GORM.
func NewGormRepository(db *gorm.DB) *GormRepository {
	return &GormRepository{db: db}
}

// Create persists a bet record.
func (r *GormRepository) Create(ctx context.Context, bet *boundary.Bet) error {
	dbBet := models.Bet{
		ID:       bet.ID,
		Username: bet.Username,
		MarketID: bet.MarketID,
		Amount:   bet.Amount,
		Outcome:  bet.Outcome,
		PlacedAt: bet.PlacedAt,
	}
	if err := r.db.WithContext(ctx).Create(&dbBet).Error; err != nil {
		return err
	}
	bet.ID = uint(dbBet.ID)
	bet.CreatedAt = dbBet.CreatedAt
	return nil
}

// UserHasBet checks whether the user has previously placed a bet in the market.
func (r *GormRepository) UserHasBet(ctx context.Context, marketID uint, username string) (bool, error) {
	var count int64
	err := r.db.WithContext(ctx).
		Model(&models.Bet{}).
		Where("market_id = ? AND username = ?", marketID, username).
		Count(&count).Error
	if err != nil {
		return false, err
	}
	return count > 0, nil
}

package bets

import (
	"context"
	"strings"
	"time"

	"socialpredict/internal/domain/boundary"
	dmarkets "socialpredict/internal/domain/markets"
	dusers "socialpredict/internal/domain/users"
)

func normalizeOutcome(outcome string) string {
	switch strings.ToUpper(strings.TrimSpace(outcome)) {
	case "YES":
		return "YES"
	case "NO":
		return "NO"
	default:
		return ""
	}
}

func validatePlaceRequest(req PlaceRequest) (string, error) {
	outcome := normalizeOutcome(req.Outcome)
	if outcome == "" {
		return "", ErrInvalidOutcome
	}
	if req.Amount <= 0 {
		return "", ErrInvalidAmount
	}
	return outcome, nil
}

func validateSellRequest(req SellRequest) (string, error) {
	outcome := normalizeOutcome(req.Outcome)
	if outcome == "" {
		return "", ErrInvalidOutcome
	}
	if req.Amount <= 0 {
		return "", ErrInvalidAmount
	}
	return outcome, nil
}

type defaultPlaceValidator struct{}

func (defaultPlaceValidator) Validate(ctx context.Context, req PlaceRequest) (string, error) {
	return validatePlaceRequest(req)
}

type defaultSellValidator struct{}

func (defaultSellValidator) Validate(ctx context.Context, req SellRequest) (string, error) {
	return validateSellRequest(req)
}

// marketGate ensures markets are open before interacting with them.
type marketGate struct {
	markets MarketReader
	clock   Clock
}

func (g marketGate) Open(ctx context.Context, marketID int64) (*dmarkets.Market, error) {
	market, err := g.markets.GetMarket(ctx, marketID)
	if err != nil {
		return nil, err
	}
	if market == nil {
		return nil, dmarkets.ErrMarketNotFound
	}
	if err := ensureMarketOpen(market, g.clock.Now()); err != nil {
		return nil, err
	}
	return market, nil
}

func ensureMarketOpen(market *dmarkets.Market, now time.Time) error {
	if market.Status == "resolved" || now.After(market.ResolutionDateTime) {
		return ErrMarketClosed
	}
	return nil
}

type feeCalculator struct {
	config Config
}

func (f feeCalculator) Calculate(hasBet bool, amount int64) betFees {
	fees := betFees{
		initialFee:     0,
		transactionFee: f.config.BuySharesFee,
	}
	if !hasBet {
		fees.initialFee = f.config.InitialBetFee
	}
	fees.totalCost = amount + fees.initialFee + fees.transactionFee
	return fees
}

type balanceGuard struct {
	maxDebtAllowed int64
}

func (g balanceGuard) EnsureSufficient(balance, totalCost int64) error {
	if balance-totalCost < -g.maxDebtAllowed {
		return ErrInsufficientBalance
	}
	return nil
}

type betLedger struct {
	repo  BetWriter
	users TransactionRecorder
}

func (l betLedger) ChargeAndRecord(ctx context.Context, bet *boundary.Bet, totalCost int64) error {
	if err := l.users.ApplyTransaction(ctx, bet.Username, totalCost, dusers.TransactionBuy); err != nil {
		return err
	}

	if err := l.repo.Create(ctx, bet); err != nil {
		_ = l.users.ApplyTransaction(ctx, bet.Username, totalCost, dusers.TransactionRefund)
		return err
	}
	return nil
}

func (l betLedger) CreditSale(ctx context.Context, bet *boundary.Bet, saleValue int64) error {
	if err := l.users.ApplyTransaction(ctx, bet.Username, saleValue, dusers.TransactionSale); err != nil {
		return err
	}
	if err := l.repo.Create(ctx, bet); err != nil {
		_ = l.users.ApplyTransaction(ctx, bet.Username, saleValue, dusers.TransactionBuy)
		return err
	}
	return nil
}

