func (serviceClock) Now() time.Time { return time.Now() }

package bets

import (
	"context"

	dusers "socialpredict/internal/domain/users"
)

// Place creates a buy bet after validating market status and user balance.
func (s *Service) Place(ctx context.Context, req PlaceRequest) (*PlacedBet, error) {
	outcome, err := s.placeValidator.Validate(ctx, req)
	if err != nil {
		return nil, err
	}
	if outcome == "" {
		return nil, ErrInvalidOutcome
	}

	if _, err := s.marketGate.Open(ctx, int64(req.MarketID)); err != nil {
		return nil, err
	}

	if s.placeUnit != nil {
		return s.placeInTransaction(ctx, req, outcome)
	}

	return s.placeWithoutTransaction(ctx, req, outcome)
}

func (s *Service) placeWithoutTransaction(ctx context.Context, req PlaceRequest, outcome string) (*PlacedBet, error) {
	user, hasBet, err := s.loadUserAndBetStatus(ctx, s.repo, s.users, req)
	if err != nil {
		return nil, err
	}

	fees := s.fees.Calculate(hasBet, req.Amount)
	if err := s.balances.EnsureSufficient(user.AccountBalance, fees.totalCost); err != nil {
		return nil, err
	}

	now := s.clock.Now()
	bet := req.NewBet(outcome, now)

	if err := s.ledger.ChargeAndRecord(ctx, bet, fees.totalCost); err != nil {
		return nil, err
	}

	return new(PlacedBet).FromModel(bet), nil
}

func (s *Service) placeInTransaction(ctx context.Context, req PlaceRequest, outcome string) (*PlacedBet, error) {
	var placed *PlacedBet
	err := s.placeUnit.PlaceBetTransaction(ctx, func(txCtx context.Context, repo Repository, users UserService) error {
		user, hasBet, err := s.loadUserAndBetStatus(txCtx, repo, users, req)
		if err != nil {
			return err
		}

		fees := s.fees.Calculate(hasBet, req.Amount)
		if err := s.balances.EnsureSufficient(user.AccountBalance, fees.totalCost); err != nil {
			return err
		}

		bet := req.NewBet(outcome, s.clock.Now())
		if err := users.ApplyTransaction(txCtx, bet.Username, fees.totalCost, dusers.TransactionBuy); err != nil {
			return err
		}
		if err := repo.Create(txCtx, bet); err != nil {
			return err
		}
		placed = new(PlacedBet).FromModel(bet)
		return nil
	})
	if err != nil {
		return nil, err
	}
	return placed, nil
}

func (s *Service) loadUserAndBetStatus(ctx context.Context, repo Repository, users UserService, req PlaceRequest) (*dusers.User, bool, error) {
	user, err := users.GetUser(ctx, req.Username)
	if err != nil {
		return nil, false, err
	}
	if user == nil {
		return nil, false, dusers.ErrUserNotFound
	}

	hasBet, err := repo.UserHasBet(ctx, req.MarketID, req.Username)
	if err != nil {
		return nil, false, err
	}

	return user, hasBet, nil
}

type betFees struct {
	initialFee     int64
	transactionFee int64
	totalCost      int64
}

func (g balanceGuard) EnsureSufficient(balance, totalCost int64) error {
	if balance-totalCost < -g.maxDebtAllowed {
		return ErrInsufficientBalance
	}
	return nil
}

type betLedger struct {
	repo  BetWriter
	users TransactionRecorder
}

func (l betLedger) ChargeAndRecord(ctx context.Context, bet *boundary.Bet, totalCost int64) error {
	if err := l.users.ApplyTransaction(ctx, bet.Username, totalCost, dusers.TransactionBuy); err != nil {
		return err
	}

	if err := l.repo.Create(ctx, bet); err != nil {
		_ = l.users.ApplyTransaction(ctx, bet.Username, totalCost, dusers.TransactionRefund)
		return err
	}
	return nil
}

func (l betLedger) CreditSale(ctx context.Context, bet *boundary.Bet, saleValue int64) error {
	if err := l.users.ApplyTransaction(ctx, bet.Username, saleValue, dusers.TransactionSale); err != nil {
		return err
	}
	if err := l.repo.Create(ctx, bet); err != nil {
		_ = l.users.ApplyTransaction(ctx, bet.Username, saleValue, dusers.TransactionBuy)
		return err
	}
	return nil
}

// ServiceInterface defines the behaviour offered by the bets domain.
type ServiceInterface interface {
	Place(ctx context.Context, req PlaceRequest) (*PlacedBet, error)
	Sell(ctx context.Context, req SellRequest) (*SellResult, error)
}

// Service implements the bets domain logic.
type Service struct {
	repo    Repository
	markets MarketService
	users   UserService
	config  Config
	clock   Clock

	placeValidator PlaceValidator
	sellValidator  SellValidator

	marketGate     MarketGate
	fees           FeeCalculator
	balances       BalanceGuard
	ledger         BetLedger
	saleCalculator SaleCalculator
	placeUnit      PlaceUnitOfWork
}

var (
	_ ServiceInterface = (*Service)(nil)
	_ SaleCalculator   = saleCalculator{}
)

// ServiceOption configures bets Service collaborators.
type ServiceOption func(*Service)

func defaultClock() Clock {
	return serviceClock{}
}

func defaultPlaceValidatorStrategy() PlaceValidator {
	return defaultPlaceValidator{}
}

func defaultSellValidatorStrategy() SellValidator {
	return defaultSellValidator{}
}

func defaultMarketGateStrategy(markets MarketReader, clock Clock) MarketGate {
	return marketGate{markets: markets, clock: clock}
}

func defaultFeeCalculatorStrategy(config Config) FeeCalculator {
	return feeCalculator{config: config}
}

func defaultBalanceGuardStrategy(config Config) BalanceGuard {
	return balanceGuard{maxDebtAllowed: config.MaximumDebtAllowed}
}

func defaultBetLedgerStrategy(repo BetWriter, users TransactionRecorder) BetLedger {
	return betLedger{repo: repo, users: users}
}

func defaultSaleCalculatorStrategy(config Config) SaleCalculator {
	return saleCalculator{maxDustPerSale: config.MaxDustPerSale}
}

func clockOrDefault(clock Clock) Clock {
	if clock == nil {
		return defaultClock()
	}
	return clock
}

func placeValidatorOrDefault(v PlaceValidator) PlaceValidator {
	if v == nil {
		return defaultPlaceValidatorStrategy()
	}
	return v
}

func sellValidatorOrDefault(v SellValidator) SellValidator {
	if v == nil {
		return defaultSellValidatorStrategy()
	}
